={{ JSON.stringify({
  model: 'gpt-5.5',
  max_completion_tokens: 300,
  temperature: 0.4,
  response_format: { type: 'json_object' },
  messages: [
    {
      role: 'system',
      content: ($('Extract Payload').first().json.promptOverride && $('Extract Payload').first().json.promptOverride.trim()) || `You are an expert ecommerce SEO and accessibility copywriter for Shopify websites.
Your task is to generate accurate, natural, and SEO-friendly alt text for website images based only on the image content and page context.
The images may include product photos, lifestyle scenes, usage scenarios, installation images, detail images, comparison images, banners, blog images, icons, or decorative visuals.
Follow these rules strictly:
1. Describe what is actually visible in the image.
2. Make the alt text helpful for users who cannot see the image.
3. Write in natural language, not as a list of keywords.
4. Keep the alt text concise, ideally 80–125 characters.
5. Do not exceed 125 characters unless necessary to clearly describe important visual information.
6. Do not use keyword stuffing.
7. Do not invent product features, certifications, benefits, or performance claims.
8. Do not mention claims such as “removes 99%,” “NSF certified,” “best,” “healthy,” “safe,” “eco-friendly,” or “top-rated” unless the claim is clearly visible in the image.
9. Do not start with “Image of,” “Photo of,” “Picture of,” or similar phrases.
10. If a product is clearly visible, include the product type, visible feature, usage scenario, or location.
11. If the image mainly shows a lifestyle or usage scene, describe the scene naturally without forcing a product name.
12. If the image is a banner or hero image, describe the main visual subject and setting.
13. If the image is an infographic, describe the main message or visible information in a concise way.
14. If the image is purely decorative and does not add meaningful information, return an empty alt text.
15. If the image contains readable text that is important to understanding the image, include the key message.
16. If the image is ambiguous, describe it cautiously and only mention what can be visually confirmed.
17. The alt text MUST be written in the language specified by the user prompt’s “Output language” field.
18. Echo back the input itemId verbatim in the "itemId" field of your JSON output. Never invent, modify, omit, or rename it.
19. Output only valid JSON in the schema specified by the user prompt. Do not include explanations outside the JSON.`
    },
    {
      role: 'user',
      content: [
        {
          type: 'text',
          text: `Input data:
itemId: ${$('Concurrency Limit (5)').item?.json?.itemId || ''}
Output language: ${$('Extract Payload').first().json.language || 'en'}
Product title, if available: ${($('Extract Payload').first().json.includeProductTitle && $('Concurrency Limit (5)').item?.json?.context?.productTitle) ? $('Concurrency Limit (5)').item.json.context.productTitle : 'N/A'}
Brand, if available: ${$('Extract Payload').first().json.brand || 'N/A'}
Keywords: ${$('Extract Payload').first().json.keywords || 'N/A'}
Image URL: ${$('Concurrency Limit (5)').item?.json?.imageUrl || ''}

Task:
Generate one accurate alt text for the image based only on the visible image content and the input data above. Follow the rules in the system prompt strictly.

JSON output schema (output exactly this shape, nothing else):
{
  "itemId": "<copy the input itemId above verbatim>",
  "altText": "<your generated alt text, or empty string if the image is purely decorative>"
}`
        },
        {
          type: 'image_url',
          image_url: { url: $('Concurrency Limit (5)').item?.json?.imageUrl, detail: 'low' }
        }
      ]
    }
  ]
}) }}

parameters.jsCode:
// runOnceForAllItems 模式：一次拿到当前 batch 的全部 OpenAI 响应 + 源 dispatch items，按 index 配对。
// 不依赖 pairedItem 元数据（HTTP Request 节点不一定写入 pairedItem，runOnceForEachItem 下
// $('Concurrency Limit (5)').item 可能为 null → 整条被丢弃，导致 Format Result 没有 output）。
//
// 数据流（v1.4 重构后）：
// - itemId 来源（权威）：sources[i].json.itemId — source by index，绝对不会错位
// - itemId 校验（可观测）：parsed.itemId — 让模型从 user prompt 把 itemId 原样回写，
//   不一致时打 warning 但仍以 source 为准，便于在 OpenAI 端按 itemId 排障
// - error 分支：模型响应不存在，只能用 source[i].itemId 兜底

const responses = $input.all();
const sources = $('Concurrency Limit (5)').all();
const executionId = $execution.id;
const out = [];

for (let i = 0; i < responses.length; i++) {
  const source = sources[i]?.json ?? {};
  const resp = responses[i]?.json ?? {};
  const itemId = source.itemId;

  // itemId 缺失：跳过这条（不应发生；防御性）
  if (!itemId) continue;

  // OpenAI 错误响应：{ error: { message, type, ... } }
  if (resp.error) {
    out.push({
      json: {
        itemId,
        status: 'error',
        errorMessage: String(resp.error.message || resp.error.type || 'OpenAI error').slice(0, 500),
        executionId
      }
    });
    continue;
  }

  // 正常响应：choices[0].message.content 是 JSON 字符串 {"itemId":"...","altText":"..."}
  const raw = resp?.choices?.[0]?.message?.content;
  let parsed = null;
  if (typeof raw === 'string') {
    try {
      parsed = JSON.parse(raw);
    } catch (e) {
      // 极端情况：模型违反 response_format=json_object → 把原文当 alt（双保险）
      parsed = { altText: raw };
    }
  }

  // 双校验：模型必须把输入的 itemId 原样回写（system prompt rule 18）。
  // 校验仅供可观测性使用；即使模型漏写/错写，itemId 仍以 source by index 为准。
  const echoed = parsed?.itemId != null ? String(parsed.itemId).trim() : '';
  if (echoed && echoed !== itemId) {
    console.warn(`[Format Result] itemId mismatch at index ${i}: source=${itemId} echoed=${echoed}`);
  }

  const alt = (typeof parsed?.altText === 'string' ? parsed.altText : '').trim();

  // 空 altText：根据 system prompt 规则 14，可能是模型判定为装饰图。
  // App 端目前不接受空 alt，所以这里映射成 error 让用户在 review 页看到原因。
  if (!alt) {
    out.push({
      json: {
        itemId,
        status: 'error',
        errorMessage: 'Decorative image or empty altText returned by model',
        executionId
      }
    });
    continue;
  }

  out.push({
    json: {
      itemId,
      status: 'ok',
      altText: alt.length > 125 ? alt.slice(0, 125) : alt,
      executionId
    }
  });
}

return out;
